# Create a release archive, excluding node_modules and .git
tar --exclude="node_modules" --exclude=".git" --exclude="deploy.sh" -czf release.tar.gz .

if [ $? -eq 0 ]; then
  echo "Archive created: release.tar.gz"

  # Send validated config to deployment orchestrator
  echo "Sending config to deployment orchestrator..."
  if command -v curl >/dev/null 2>&1; then
    # Convert .env.test to JSON and send
    JSON_CONFIG=$(node -e "
      const fs = require('fs');
      const env = fs.readFileSync('.env.test', 'utf8');
      const config = {};
      env.split('\n').forEach(line => {
        if (line.trim() && !line.startsWith('#')) {
          const [key, value] = line.split('=', 2);
          if (key) config[key.trim()] = value ? value.trim() : '';
        }
      });
      console.log(JSON.stringify(config));
    ")

    curl -X POST http://localhost:3003/api/deploy-config \
      -H "Content-Type: application/json" \
      -d "$JSON_CONFIG"

    if [ $? -eq 0 ]; then
      echo "Config sent successfully"
    else
      echo "Warning: Failed to send config to orchestrator"
    fi
  else
    echo "Warning: curl not available. Cannot send config to orchestrator."
  fi
else
  echo "Error creating archive"
  exit 1
fi
